"""Shared helpers for the unified eval runner (eval.run)."""
from __future__ import annotations

import json
import statistics
from pathlib import Path

from . import attacks, config, null_inputs
from .deliverable import Bundle
from .rubric import RubricItem

# Where rollout deliverables generated by eval.policy are written.
ROLLOUTS = config.ROOT / "eval" / "rollouts"

# --- axis thresholds (shared by the judge runner and the iterator) ----------
LEAK_THRESHOLD = 0.5      # a null earning >=50% of a positive item's points = leak
NULL_HACK_SCORE = 0.30    # a null scoring above this is a reward-hacking suspect


def load_task(task_folder: str) -> dict:
    return json.loads((config.DATA / task_folder / "task.json").read_text())


def has_gold(task_folder: str) -> bool:
    return bool(load_task(task_folder).get("deliverable_files"))


def reference_dir(task_folder: str) -> Path:
    return config.DATA / task_folder / "reference_files"


def gold_bundle(task_folder: str) -> Bundle:
    return Bundle.with_references(
        "gold",
        config.DATA / task_folder / "deliverable_files",
        reference_dir(task_folder),
    )


def null_bundle(task_folder: str, variant: str, variant_dir: Path) -> Bundle:
    """Wrap a synthesized null deliverable with the same read-only reference files."""
    return Bundle.with_references(variant, variant_dir, reference_dir(task_folder))


def rollout_dir(task_folder: str, policy_key: str) -> Path:
    """Directory holding a policy's generated deliverable files for a task."""
    return ROLLOUTS / task_folder / policy_key / "deliverable"


# --- subject resolution -----------------------------------------------------
# A "subject" is whatever a judge grades, named by a short string on the CLI:
#   gold                      the released gold deliverable (oracle, ~1)
#   blank | unedited_input    a synthesized do-nothing null (~0); from null_inputs
#   attack:<name> | <name>    a mechanical reward-hacking deliverable; from attacks
#                             (restate_input | keyword_stuff | presence_max | stems_named)
#   rollout:<policy_key>      a deliverable produced by eval.policy for <policy_key>
#   preexisting:<path>        files under <path> (or <path>/<task_folder>)

def available_subjects(task_folder: str) -> list[str]:
    """The default boundary subjects for a task: gold plus any synthesized nulls."""
    subs = ["gold"] if has_gold(task_folder) else []
    subs += list(null_inputs.build_nulls(task_folder))
    return subs


def attack_subjects(task_folder: str) -> list[str]:
    """The hackability attack subjects for a task (Axis 2). Needs no gold."""
    return attacks.attack_names(task_folder)


def hack_subjects(task_folder: str) -> list[str]:
    """Cheap subjects whose passing a positive item counts as a leak: nulls + attacks."""
    return list(null_inputs.build_nulls(task_folder)) + attack_subjects(task_folder)


def resolve_subject(task_folder: str, subject: str) -> Bundle:
    """Map a subject string to a gradeable Bundle (deliverable + read-only references)."""
    if subject == "gold":
        if not has_gold(task_folder):
            raise SystemExit(f"{task_folder}: no gold deliverable released")
        return gold_bundle(task_folder)

    if subject.startswith("rollout:"):
        key = subject.split(":", 1)[1]
        d = rollout_dir(task_folder, key)
        if not d.exists() or not any(d.iterdir()):
            raise SystemExit(
                f"{task_folder}: no rollout for policy '{key}' "
                f"(run --mode rollout --policy-models {key} first)")
        return Bundle.with_references(subject, d, reference_dir(task_folder))

    if subject.startswith("preexisting:"):
        root = Path(subject.split(":", 1)[1]).expanduser()
        d = root / task_folder if (root / task_folder).is_dir() else root
        if not d.is_dir():
            raise SystemExit(f"{task_folder}: no preexisting outputs at {d}")
        return Bundle.with_references(subject, d, reference_dir(task_folder))

    # attack:<name> or a bare attack variant name (hackability subjects, Axis 2)
    name = subject.split(":", 1)[1] if subject.startswith("attack:") else subject
    atk = attacks.build_attacks(task_folder)
    if name in atk:
        return Bundle.with_references(subject, atk[name], reference_dir(task_folder))

    # otherwise treat it as a null variant name (blank / unedited_input / ...)
    nulls = null_inputs.build_nulls(task_folder)
    if subject not in nulls:
        raise SystemExit(
            f"{task_folder}: unknown subject '{subject}' (have: gold, "
            f"{', '.join(nulls) or 'no nulls'}, {', '.join(atk) or 'no attacks'}, "
            f"rollout:<key>, preexisting:<path>)")
    return null_bundle(task_folder, subject, nulls[subject])


def is_null_subject(task_folder: str, subject: str) -> bool:
    """True for synthesized do-nothing nulls (used by the boundary analysis)."""
    return subject in null_inputs.build_nulls(task_folder)


def is_attack_subject(task_folder: str, subject: str) -> bool:
    """True for mechanical reward-hacking attacks (used by the hackability analysis)."""
    name = subject.split(":", 1)[1] if subject.startswith("attack:") else subject
    return name in attacks.attack_names(task_folder)


def all_tasks() -> list[str]:
    return sorted(p.name for p in config.DATA.iterdir() if p.is_dir())


def tasks_with_gold() -> list[str]:
    return [t for t in all_tasks() if has_gold(t)]


def stdev(xs: list[float]) -> float:
    return statistics.pstdev(xs) if len(xs) > 1 else 0.0


# --- shared dispersion / boundary analysis ----------------------------------
# Used by both the judge runner (eval.run) and the rubric iterator (eval.iterate).

def agreement(items: list[RubricItem], runs: list[dict]) -> dict:
    """Per-item dispersion across a set of scorecards (binarized at 0.5).

    `runs` are normalize() dicts for the SAME subject (different judges for
    cross-model, or repeats of one judge for self-consistency)."""
    per_item = []
    for it in items:
        fracs = [r["per_item"][it.id]["fraction"] for r in runs]
        binar = [1 if f >= 0.5 else 0 for f in fracs]
        per_item.append({
            "id": it.id, "criterion": it.criterion,
            "mean": round(sum(fracs) / len(fracs), 3),
            "stdev": round(stdev(fracs), 3),
            "unanimous": len(set(binar)) == 1,
        })
    totals = [r["normalized"] for r in runs]
    frac_unanimous = sum(1 for p in per_item if p["unanimous"]) / len(per_item)
    return {
        "total_scores": [round(t, 3) for t in totals],
        "total_mean": round(sum(totals) / len(totals), 3),
        "total_stdev": round(stdev(totals), 3),
        "frac_items_unanimous": round(frac_unanimous, 3),
        "mean_item_stdev": round(sum(p["stdev"] for p in per_item) / len(per_item), 3),
        "per_item": per_item,
        "most_contested": sorted(per_item, key=lambda p: -p["stdev"])[:8],
    }


def leaks(items: list[RubricItem], null_runs: list[dict]) -> list[dict]:
    """Positive items a do-nothing null still earns >= LEAK_THRESHOLD (form/presence rewards)."""
    out = []
    for it in items:
        if it.max_score <= 0:
            continue  # penalties aren't "passed" by doing nothing
        null_max = max((r["per_item"][it.id]["fraction"] for r in null_runs), default=0.0)
        if null_max >= LEAK_THRESHOLD:
            out.append({"id": it.id, "criterion": it.criterion,
                        "null_fraction": round(null_max, 2)})
    return out


def write_tsv(path: Path, header: list[str], rows: list[list]):
    with open(path, "w") as f:
        f.write("\t".join(header) + "\n")
        for r in rows:
            f.write("\t".join(str(x) for x in r) + "\n")
    print(f"  wrote {path.relative_to(config.ROOT)}  ({len(rows)} rows)")

"""Thin OpenAI-compatible chat client that works for both OpenAI and OpenRouter.

Exposes one function, `chat`, that handles the per-provider parameter quirks
(GPT-5 reasoning models reject `temperature`/`max_tokens`) and records spend.
"""
from __future__ import annotations

import json
import time
from typing import Any

from openai import OpenAI, BadRequestError

from . import config
from .config import CostTracker
from .models import Model

_CLIENTS: dict[str, OpenAI] = {}


# --- tool-call hygiene ------------------------------------------------------
# Some OpenRouter providers (seen with qwen3.6, mimo) emit malformed `arguments`
# JSON — trailing junk after the object ("Extra data") or a truncated string
# ("Unterminated string"). Echoing that verbatim in the next request makes the
# strict provider 400 the whole call. We parse tolerantly and ALWAYS re-serialize.

def parse_tool_args(raw: str | None) -> dict:
    """Best-effort parse of a tool call's `arguments` string into a dict.

    Recovers the leading object from 'Extra data' cases via raw_decode; returns {}
    for anything unrecoverable (e.g. a truncated/unterminated string)."""
    s = (raw or "").strip()
    if not s:
        return {}
    try:
        v = json.loads(s)
    except json.JSONDecodeError:
        try:
            v, _ = json.JSONDecoder().raw_decode(s)
        except Exception:
            return {}
    return v if isinstance(v, dict) else {}


def assistant_tool_calls(tcs) -> tuple[list[dict] | None, dict[str, dict]]:
    """Turn raw model tool_calls into a replay-safe assistant payload.

    Every echoed call gets a re-serialized (guaranteed-valid) `arguments` string;
    nameless calls are dropped. Returns (payload_or_None, {tool_call_id: parsed_args})
    so callers reuse the exact args we will replay."""
    payload, parsed = [], {}
    for tc in tcs:
        name = getattr(getattr(tc, "function", None), "name", None)
        if not name:
            continue
        args = parse_tool_args(tc.function.arguments)
        parsed[tc.id] = args
        payload.append({"id": tc.id, "type": "function",
                        "function": {"name": name, "arguments": json.dumps(args)}})
    return (payload or None), parsed


def _client(model: Model) -> OpenAI:
    if model.provider not in _CLIENTS:
        if model.provider == "openai":
            _CLIENTS["openai"] = OpenAI(api_key=config.OPENAI_API_KEY)
        elif model.provider == "openrouter":
            _CLIENTS["openrouter"] = OpenAI(
                api_key=config.OPENROUTER_API_KEY,
                base_url="https://openrouter.ai/api/v1",
            )
        else:
            raise ValueError(f"unknown provider {model.provider}")
    return _CLIENTS[model.provider]


def chat(
    model: Model,
    messages: list[dict],
    tools: list[dict] | None = None,
    tool_choice: Any = None,
    temperature: float = 0.0,
    max_tokens: int = 4096,
    retries: int = 4,
):
    """Return a raw chat completion `message` object (with .content / .tool_calls)."""
    client = _client(model)
    kwargs: dict[str, Any] = {"model": model.model_id, "messages": messages}
    if tools:
        kwargs["tools"] = tools
        if tool_choice is not None:
            kwargs["tool_choice"] = tool_choice

    if model.is_reasoning:
        kwargs["max_completion_tokens"] = max_tokens
        # reasoning models only accept the default temperature; omit it
    else:
        kwargs["max_tokens"] = max_tokens
        kwargs["temperature"] = temperature

    last_err = None
    for attempt in range(retries):
        try:
            resp = client.chat.completions.create(**kwargs)
            u = getattr(resp, "usage", None)
            if u:
                CostTracker.add(
                    getattr(u, "prompt_tokens", 0) or 0,
                    getattr(u, "completion_tokens", 0) or 0,
                    model.in_price, model.out_price,
                )
            return resp.choices[0].message
        except BadRequestError as e:
            # Drop a param the model dislikes and retry once before giving up.
            msg = str(e).lower()
            if "temperature" in msg and "temperature" in kwargs:
                kwargs.pop("temperature"); continue
            if "max_tokens" in msg and "max_tokens" in kwargs:
                kwargs["max_completion_tokens"] = kwargs.pop("max_tokens"); continue
            # OpenRouter "provider returned error" 400s are often a single flaky
            # upstream provider; a retry may route to a healthy one.
            if ("provider returned error" in msg or "extra data" in msg) \
                    and attempt < retries - 1:
                last_err = e
                time.sleep(2 * (attempt + 1)); continue
            last_err = e
            break
        except Exception as e:  # rate limits, transient 5xx
            last_err = e
            time.sleep(2 * (attempt + 1))
    raise RuntimeError(f"chat failed for {model.key}: {last_err}")

"""A Bundle wraps the set of files a judge may inspect for one deliverable.

It abstracts over file type and over zip containers, so the agent tools can
refer to everything by a flat logical name (e.g. "stems.zip/lead_vocal.wav").
"""
from __future__ import annotations

import zipfile
from dataclasses import dataclass, field
from pathlib import Path

import fitz  # pymupdf

from . import config

TEXT_EXT = {".pdf", ".docx", ".txt", ".md", ".srt"}
IMAGE_EXT = {".jpg", ".jpeg", ".png", ".webp", ".gif"}
AUDIO_EXT = {".wav", ".mp3", ".m4a", ".aac", ".flac"}
VIDEO_EXT = {".mp4", ".mov", ".mkv", ".webm"}


def kind(name: str) -> str:
    ext = Path(name).suffix.lower()
    if ext in IMAGE_EXT:
        return "image"
    if ext in AUDIO_EXT:
        return "audio"
    if ext in VIDEO_EXT:
        return "video"
    if ext in TEXT_EXT:
        return "document"
    if ext == ".zip":
        return "archive"
    return "other"


@dataclass
class Bundle:
    label: str
    files: dict[str, Path] = field(default_factory=dict)  # logical name -> real path
    roles: dict[str, str] = field(default_factory=dict)   # logical name -> "deliverable"|"reference"
    _extract_dir: Path | None = None

    @classmethod
    def from_dir(cls, label: str, directory: Path, expand_zip_media: bool = True,
                 role: str = "deliverable") -> "Bundle":
        b = cls(label=label)
        b._ingest(directory, role, expand_zip_media)
        return b

    @classmethod
    def with_references(cls, label: str, deliverable_dir: Path, reference_dir: Path | None,
                        expand_zip_media: bool = True) -> "Bundle":
        """Deliverable files (graded) plus read-only reference/input files (for comparison)."""
        b = cls(label=label)
        b._ingest(deliverable_dir, "deliverable", expand_zip_media)
        if reference_dir is not None:
            b._ingest(reference_dir, "reference", expand_zip_media)
        return b

    def _ingest(self, directory: Path, role: str, expand_zip_media: bool) -> None:
        if not directory or not directory.exists():
            return
        for p in sorted(directory.iterdir()):
            if p.is_file():
                self.files[p.name] = p
                self.roles[p.name] = role
                if expand_zip_media and p.suffix.lower() == ".zip":
                    before = set(self.files)
                    self._expand_zip(p)
                    for k in set(self.files) - before:
                        self.roles[k] = role

    def _expand_zip(self, zpath: Path) -> None:
        extract_root = config.CACHE / f"zip_{zpath.stem}"
        try:
            with zipfile.ZipFile(zpath) as zf:
                for member in zf.namelist():
                    if member.endswith("/"):
                        continue
                    base = Path(member).name
                    # Skip macOS archive cruft (AppleDouble resource forks, __MACOSX).
                    if base.startswith("._") or "__MACOSX" in member:
                        continue
                    if kind(member) in ("audio", "video", "image", "document"):
                        target = extract_root / member
                        if not target.exists():
                            target.parent.mkdir(parents=True, exist_ok=True)
                            with zf.open(member) as src, open(target, "wb") as dst:
                                dst.write(src.read())
                        logical = f"{zpath.name}/{Path(member).name}"
                        self.files[logical] = target
        except zipfile.BadZipFile:
            pass

    # --- introspection -----------------------------------------------------
    def listing(self, role: str | None = None) -> list[dict]:
        out = []
        for name, path in self.files.items():
            r = self.roles.get(name, "deliverable")
            if role is not None and r != role:
                continue
            out.append({
                "name": name,
                "type": kind(name),
                "role": r,
                "size_kb": round(path.stat().st_size / 1024, 1),
            })
        return out

    def resolve(self, name: str, role: str | None = None) -> Path:
        """Resolve a logical name to a path, optionally restricted to one role.

        Restricting to role='deliverable' is how we stop a judge from loading a
        reference INPUT through a grading tool and scoring it as the output."""
        names = {k: p for k, p in self.files.items()
                 if role is None or self.roles.get(k, "deliverable") == role}
        if name in names:
            return names[name]
        for k, p in names.items():  # tolerate basename-only refs from the model
            if Path(k).name == name:
                return p
        # Give a pointed message if it exists but in the other role.
        if role == "deliverable" and (name in self.files or
                any(Path(k).name == name for k in self.files)):
            raise FileNotFoundError(
                f"'{name}' is a REFERENCE input, not part of the graded deliverable. "
                f"Use read_reference/view_reference to consult it for comparison only.")
        raise FileNotFoundError(f"{name} not in bundle {self.label}: {list(names)}")


# --- text extraction --------------------------------------------------------
def extract_text(path: Path) -> str:
    ext = path.suffix.lower()
    if ext == ".pdf":
        doc = fitz.open(path)
        parts = []
        for i, page in enumerate(doc):
            parts.append(f"--- page {i + 1} ---\n{page.get_text()}")
        return "\n".join(parts).strip() or "[PDF has no extractable text layer]"
    if ext in (".txt", ".md", ".srt"):
        return path.read_text(errors="replace")
    if ext == ".docx":
        return _docx_text(path)
    return f"[no text extractor for {ext}]"


def _docx_text(path: Path) -> str:
    import re
    import zipfile as zf
    try:
        with zf.ZipFile(path) as z:
            xml = z.read("word/document.xml").decode("utf-8", "replace")
    except Exception as e:
        return f"[docx read failed: {e}]"
    xml = re.sub(r"</w:p>", "\n", xml)
    xml = re.sub(r"<w:tab[^>]*/>", "\t", xml)
    text = re.sub(r"<[^>]+>", "", xml)
    return re.sub(r"\n{3,}", "\n\n", text).strip()


def pdf_page_png(path: Path, page: int, zoom: float = 1.6) -> str:
    import base64
    doc = fitz.open(path)
    page = max(0, min(page, doc.page_count - 1))
    pix = doc[page].get_pixmap(matrix=fitz.Matrix(zoom, zoom))
    return base64.b64encode(pix.tobytes("png")).decode()


def pdf_page_count(path: Path) -> int:
    return fitz.open(path).page_count


def file_facts(path: Path) -> dict:
    """Deterministic, non-guessable facts: extension, size, page/word counts.

    Lets the judge answer 'is it a PDF?', 'is it <= 2 pages?', 'word count'
    without inferring from a rendering."""
    facts = {
        "name": path.name,
        "extension": path.suffix.lower(),
        "type": kind(path.name),
        "size_kb": round(path.stat().st_size / 1024, 1),
    }
    if path.suffix.lower() == ".pdf":
        doc = fitz.open(path)
        facts["page_count"] = doc.page_count
        facts["word_count"] = sum(len(p.get_text().split()) for p in doc)
    elif path.suffix.lower() in (".docx", ".txt", ".md", ".srt"):
        facts["word_count"] = len(extract_text(path).split())
    return facts

def duration_seconds(path: Path) -> float:
    try:
        out = subprocess.run(
            ["ffprobe", "-v", "error", "-show_entries", "format=duration",
             "-of", "json", str(path)],
            check=True, capture_output=True, text=True,
        ).stdout
        return float(json.loads(out)["format"]["duration"])
    except Exception:
        return 0.0


def probe(path: Path) -> dict:
    """Deterministic media facts via ffprobe (container, codecs, resolution, fps, ...).

    This exists so the judge never has to *guess* objective technical criteria
    ('codec is H.264', 'resolution is 1920x1080', 'runtime 29.9-30.1s')."""
    try:
        out = subprocess.run(
            ["ffprobe", "-v", "error", "-show_format", "-show_streams",
             "-of", "json", str(path)],
            check=True, capture_output=True, text=True,
        ).stdout
        raw = json.loads(out)
    except Exception as e:
        return {"error": f"ffprobe failed: {e}"}
    fmt = raw.get("format", {})
    facts: dict = {
        "container": fmt.get("format_name"),
        "duration_s": round(float(fmt.get("duration", 0) or 0), 3),
        "size_bytes": int(fmt.get("size", 0) or 0),
        "bit_rate": fmt.get("bit_rate"),
        "video": [], "audio": [],
    }
    for s in raw.get("streams", []):
        if s.get("codec_type") == "video":
            num, den = (s.get("r_frame_rate", "0/1").split("/") + ["1"])[:2]
            fps = round(float(num) / float(den), 2) if float(den) else None
            facts["video"].append({
                "codec": s.get("codec_name"),
                "width": s.get("width"), "height": s.get("height"),
                "fps": fps, "pix_fmt": s.get("pix_fmt"),
            })
        elif s.get("codec_type") == "audio":
            facts["audio"].append({
                "codec": s.get("codec_name"),
                "sample_rate": s.get("sample_rate"),
                "channels": s.get("channels"),
            })
    return facts


def b64(path: Path) -> str:
    return base64.b64encode(path.read_bytes()).decode()


# --- frames ---------------------------------------------------------------
def _nonempty(paths: list[Path]) -> list[Path]:
    return [p for p in paths if p.exists() and p.stat().st_size > 0]


def video_frames(path: Path, n: int = 10, width: int = 768,
                 start: float | None = None, end: float | None = None) -> list[Path]:
    """n evenly-spaced JPEG frame files, optionally within a [start,end] window.

    Higher default resolution + count than before so on-screen text and distinct
    shots are actually legible/visible. Returns paths; the caller validates/encodes."""
    dur = duration_seconds(path) or 1.0
    a = 0.0 if start is None else max(0.0, start)
    b = dur if end is None else min(dur, end)

def tool_schemas(model: Model) -> list[dict]:
    """The toolbox advertised to this model (only what its modalities can use)."""
    t: list[dict] = [
        {"type": "function", "function": {
            "name": "list_files",
            "description": "List every file in the deliverable (and media inside archives).",
            "parameters": {"type": "object", "properties": {}},
        }},
        {"type": "function", "function": {
            "name": "read_text",
            "description": "Extract the text of a PDF / DOCX / TXT file.",
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"}}, "required": ["name"]},
        }},
        {"type": "function", "function": {
            "name": "transcribe_audio",
            "description": "Speech-to-text transcript of an audio or video file's audio track.",
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"}}, "required": ["name"]},
        }},
        {"type": "function", "function": {
            "name": "file_facts",
            "description": ("Deterministic facts about a file: exact extension/type, size, "
                            "PDF page count, and word count. Use this for objective criteria "
                            "(is it a PDF? is it <=2 pages? word count) instead of guessing."),
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"}}, "required": ["name"]},
        }},
        {"type": "function", "function": {
            "name": "probe_media",
            "description": ("Ground-truth technical facts (ffprobe) for an audio/video file: "
                            "container, codec, exact resolution, fps, duration in seconds, "
                            "audio channels/sample rate AND bit depth (pcm_s24le = 24-bit). "
                            "Use for codec/resolution/runtime/sample-rate/bit-depth criteria."),
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"}}, "required": ["name"]},
        }},
        {"type": "function", "function": {
            "name": "analyze_audio",
            "description": ("Measured audio/music facts (DSP) you must NOT guess: integrated "
                            "loudness (LUFS), true peak (dBFS), tempo (BPM), estimated musical "
                            "key, and harmonic fraction. Use for tempo/key/loudness/fidelity/"
                            "instrumental criteria. Numbers are estimates; combine with listening."),
            "parameters": {"type": "object", "properties": {
                "name": {"type": "string"}}, "required": ["name"]},
        }},
        {"type": "function", "function": {
            "name": "compare_audio_sync",
            "description": ("Measure timing alignment between a deliverable audio file and a "
                            "REFERENCE track (e.g. a drum reference): start offset (ms), tail "
                            "offset (ms), and end-to-end drift (ms). Use for 'synchronized to' "
                            "and 'drift <= N ms' criteria."),
            "parameters": {"type": "object", "properties": {
