        return f"ERROR running {name}: {e}", []


def _dispatch(name: str, args: dict, bundle: D.Bundle) -> tuple[str, list[dict]]:
    DEL = "deliverable"  # grading tools must only ever touch the deliverable

    if name == "list_files":
